  },
  {
    "id": "fb6e2ddb-450d-4fc0-a132-6c0816a346a0",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "left"
    },
    "content": [],
    "children": []
  },
  {
    "id": "be9e813f-be5f-4893-b791-653911dd6b76",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "left"
    },
    "content": [],
    "children": []
  },
  {
    "id": "63fcc158-9a39-4e21-b659-8f3650d5d334",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "interface EditorProps { \nonChange: (value: string) => void; \ninitialContent?: string; \neditable?: boolean; \neditorFont?: string; \nsmallText?: boolean; \nonEditorReady?: (editor: BlockNoteEditor) => void; \n}",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "159d6b5d-31c5-4996-b9ae-acaddbe1144b",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "// Use default schema and extend with code block \nconst schema = BlockNoteSchema.create({ \nblockSpecs: { \n// Keep all default blocks \n...defaultBlockSchema.blockSpecs, \n// Add code block \ncodeBlock: createCodeBlockSpec({ \n...codeBlockOptions, \ndefaultLanguage: \"typescript\", \nsupportedLanguages: { \ntypescript: { name: \"TypeScript\", aliases: [\"ts\"] }, \njavascript: { name: \"JavaScript\", aliases: [\"js\"] }, \npython: { name: \"Python\", aliases: [\"py\"] }, \ncpp: { name: \"C++\", aliases: [\"cpp\", \"c++\"] }, \njava: { name: \"Java\" }, \nrust: { name: \"Rust\", aliases: [\"rs\"] }, \ngo: { name: \"Go\" }, \nsql: { name: \"SQL\" }, \nhtml: { name: \"HTML\" }, \ncss: { name: \"CSS\" }, \n}, \n}), \n}, \n});",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "e0c1b177-a6f9-4b5d-ba37-70a80591fb39",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const MEDIA_BLOCK_TYPES = new Set([\"image\", \"video\", \"audio\", \"file\"]);",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "be594f47-3bb5-401d-a3fe-92119054216f",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const getMediaUrls = (editor: BlockNoteEditor): Set => { \nconst urls = new Set();",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "0075d1b1-ccc8-4e1f-8b6b-dfa8b3462c25",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "editor.forEachBlock((block) => { \nif (MEDIA_BLOCK_TYPES.has(block.type)) { \nconst url = (block.props as any)?.url; \nif (url && typeof url === \"string\" && url.trim() !== \"\") { \nurls.add(url); \n} \n} \nreturn true; \n});",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "94220e90-4c78-41bc-9afb-c8dd5e6e0a19",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "return urls; \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "35f7a8d4-9357-499e-a3e9-086aadd508ad",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const Editor = ({ \nonChange, \ninitialContent, \neditable = true, \neditorFont, \nsmallText = false, \nonEditorReady, \n}: EditorProps) => { \nconst { resolvedTheme } = useTheme(); \nconst { edgestore } = useEdgeStore();",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "c70edef9-d18b-484d-8c1a-dafa753050ec",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const coverImage = useCoverImage(); \nconst wordCount = useWordCount();",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "52d68843-e6cb-4626-8f2a-d092d5396e09",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const wrapperRef = useRef(null); \nconst trackedUrlsRef = useRef<Set>(new Set()); \nconst isUploadingRef = useRef(false);",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "6e7432d8-573e-4b24-8635-e7abdd8b7a86",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const handleUpload = async (file: File) => { \nif (isUploadingRef.current) { \nreturn Promise.reject(\"Upload already in progress\"); \n}",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "828167ad-7c4e-49e8-a19c-c58387fb8234",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "try { \nisUploadingRef.current = true;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "f5118b57-cb2b-4fd2-8541-a2405ed20ff8",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "console.log(\"Uploading file:\", ",
        "styles": {}
      },
      {
        "type": "link",
        "href": "https://file.name",
        "content": [
          {
            "type": "text",
            "text": "file.name",
            "styles": {}
          }
        ]
      },
      {
        "type": "text",
        "text": ", file.type, file.size);",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "4737e473-ec35-45de-a594-14ea6fe0cd4b",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const res = await edgestore.publicFiles.upload({ file });",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "52e16ad1-a19c-491f-8bd6-8698341772f4",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "return res.url; \n} catch (error) { \nconsole.error(\"Upload failed:\", error); \nthrow error; \n} finally { \nisUploadingRef.current = false; \n} \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "25d3fc79-1c8c-4fdd-a48a-08e43e227945",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const getWords = () => { \nlet count: number = 0; \neditor.forEachBlock((block) => { \nif ( \nblock.type === \"paragraph\" || \nblock.type === \"heading\" || \nblock.type === \"quote\" || \nblock.type === \"bulletListItem\" || \nblock.type === \"checkListItem\" || \nblock.type === \"numberedListItem\" || \nblock.type === \"toggleListItem\" \n) { \nconst words = block.content \n.filter((c) => c.type === \"text\") \n.map((c) => c.text) \n.join(\" \") \n.trim() \n.split(/\\s+/) \n.filter((word) => /[a-zA-Z0-9]/.test(word));",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "bda03e47-413a-48c2-bc02-a0674f705061",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "count += words.length; \n}",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "8e520e79-f12a-4b6d-8409-7a7e53918bcd",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "if (block.type === \"table\") { \nblock.content.rows.forEach((row) => { \nrow.cells.forEach((cell: any) => { \nconst words = cell.content \n.filter((c: any) => c.type === \"text\") \n.map((c: any) => c.text) \n.join(\" \") \n.trim() \n.split(/\\s+/) \n.filter((word: string) => /[a-zA-Z0-9]/.test(word));",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "40e04882-fdfc-4879-9c8e-d363ffd1a643",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "count += words.length; \n}); \n}); \n}",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "3e5ca171-61b3-481f-bfdb-a98adcebbba2",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "return true; \n}); \nwordCount.setWordCount(count); \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "f990433e-496d-45d2-a7f5-b503450382d3",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const editor: BlockNoteEditor = useCreateBlockNote({ \ninitialContent: initialContent \n? (JSON.parse(initialContent) as PartialBlock[]) \n: undefined, \nuploadFile: handleUpload, \nschema, \n});",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "beac0c70-8615-401c-9f1f-fbd50c9c8bbf",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "left"
    },
    "content": [],
    "children": []
  },
  {
    "id": "e4c6e370-3355-4f5b-9d55-ea775a197dab",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "useEffect(() => { \nif (editor) { \ntrackedUrlsRef.current = getMediaUrls(editor); \ngetWords(); \n} \nif (editor && onEditorReady) { \nonEditorReady(editor); \n} \n}, [editor]);",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "c256ac5e-0d32-46f1-9135-e6e011c75933",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const handleEditorChange = () => { \nconst currentUrls = getMediaUrls(editor); \nconst previousUrls = trackedUrlsRef.current;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "e0923bab-fa67-44df-ade7-bb87169be6e0",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const removedUrls = [...previousUrls].filter( \n(url) => !currentUrls.has(url), \n);",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "73262140-61a0-4ab0-99c5-33b2057fdbca",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "removedUrls.forEach((url) => { \nedgestore.publicFiles.delete({ url }).catch((err) => { \nconsole.warn(\"Failed to delete file in edgestore:\", url, err); \n}); \n}); \ntrackedUrlsRef.current = currentUrls;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "1fd9f9a8-015e-41c4-9d13-b1debb632af1",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "getWords();",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "5bec368a-2105-429a-8c5b-d8c3ec095bbe",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "onChange(JSON.stringify(editor.document, null, 2)); \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "ae8a5430-34f6-4355-b9a7-9340575d8611",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const handleCapture = (e: React.DragEvent) => { \nif (coverImage.isOpen) { \ne.preventDefault(); \ne.stopPropagation(); \n} \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "c7ecda29-ef42-483f-bc36-e111b8d9f6a5",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const handleMouseDown = (e: React.MouseEvent) => { \nif (!editable || coverImage.isOpen) return;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "a0137e1d-5ef1-4148-a61a-f7edf14af6d4",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const blockEl = (",
        "styles": {}
      },
      {
        "type": "link",
        "href": "https://e.target",
        "content": [
          {
            "type": "text",
            "text": "e.target",
            "styles": {}
          }
        ]
      },
      {
        "type": "text",
        "text": " as HTMLElement).closest( \n\"[data-node-type='blockContainer']\", \n); \nif (!blockEl) return;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "20bdc006-c65b-412b-a64e-d202c7292526",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const blockId = blockEl.getAttribute(\"data-id\"); \nif (!blockId) return;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "518eaad6-777d-46af-b7f2-be83cf3b13d2",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const currentBlock = editor.getBlock(blockId); \nif (!currentBlock) return; \nconst prevBlock = editor.getPrevBlock(blockId); \nif (!prevBlock) return;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "6cb88a6c-de07-47ac-89a6-909786d318df",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "if (!MEDIA_BLOCK_TYPES.has(prevBlock?.type as string)) return;",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "4055d530-dbf4-4464-b68c-6c516851e8dd",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "e.stopPropagation();",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "7c31b59e-0687-4e74-aa56-c85ceecf78f2",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "const view = (editor as any)._tiptapEditor.view; \nconst pos = view.posAtCoords({ left: e.clientX, top: e.clientY });",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "8a9ebf49-3af8-44f8-8a7c-00a0f6eb7db5",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "if (pos) { \nview.dispatch( \nview.state.tr.setSelection( \nview.state.selection.constructor.near( \nview.state.doc.resolve(pos.pos), \n), \n), \n); \n} \neditor.focus(); \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "23f65cc0-7917-4d65-9417-806c17add3a5",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "return ( \n<div \nref={wrapperRef} \nclassName=\"relative flex-1 shrink-0 px-0 pb-10\" \nstyle={ \n{ \n\"--editor-font\": fontFamilies[editorFont as EditorFont], \n\"--editor-font-size\": smallText ? \"15px\" : \"16px\", \n} as React.CSSProperties \n} \nonDropCapture={handleCapture} \nonDragOverCapture={handleCapture} \nonMouseDown={handleMouseDown} \n> \n<BlockNoteView \neditable={editable && !coverImage.isOpen} \neditor={editor} \ntheme={resolvedTheme === \"dark\" ? \"dark\" : \"light\"} \nonChange={handleEditorChange} \nclassName=\"wrap-break-word\" \n/> \n\n); \n};",
        "styles": {}
      }
    ],
    "children": []
  },
  {
    "id": "af819a85-a223-4557-b292-3f0ef6dad2a8",
    "type": "paragraph",
    "props": {
      "backgroundColor": "default",
      "textColor": "default",
      "textAlignment": "center"
    },
    "content": [
      {
        "type": "text",
        "text": "export default Editor;",
        "styles": {}
      }
    ],
    "children": []
  },
